  The standard unramified section \(\Phi(-,s) \in I_n(s, \chi)\) is the unique
  \(K = H_n(\hat{\cO})\)-invariant section with \(\Phi(1_{2n}, s) = 1\). The
  \emph{Siegel--Eisenstein series} is
  \[
    E(g, s, \Phi) = \sum_{\gamma \in P_n(F) \backslash H_n(F)} \Phi(\gamma g, s),
    \quad g \in H_n(\BA),
  \]
  converging absolutely for \(\mathrm{Re}(s) \gg 0\) and admitting meromorphic
  continuation to all \(s \in \mathbf{C}\).
\end{definition}

\section{Fourier expansion}

\begin{definition}[Fourier coefficient]
  \label{def:fourier-coefficient}
  \lean{HSW.FourierCoefficient}
  \uses{def:siegel-eisenstein-series, def:hermitian-spaces}
  % SOURCE: [FYZ], §2.2 Fourier expansion (read from references/MR4689373-siegel-weil-unitary.tex)
  % SOURCE QUOTE: We have a Fourier expansion $E(g,s,\Phi)=\sum_{T\in\Herm_n(F,\om_{F})}E_T(g,s,\Phi),$ where $E_T(g,s,\Phi)=\int_{N_n(F)\backslash N_n(\mathbb{A})} E(n(b)g,s,\Phi)\psi_{0}(\j{T,b})\,\rd n(b),$ and the Haar measure $\rd n(b)$ is normalized such that $N_{n}(F)\bs N_{n}(\BA)$ has volume $1$. ... Suppose $T$ is \emph{nonsingular}, meaning that for one (equivalently, any) choice of trivialization of $\omega_F$ it has non-vanishing determinant, for a factorizable $\Phi=\bigotimes_{v\in|X|}\Phi_v$ we have a factorization of the Fourier coefficient into a product (cf. \cite[\S 4]{Kudla1997}) $E_T(g,s,\Phi)=|\om_{X}|_{F}^{-n^{2}/2}\prod_v W_{T,v}(g_v, s, \Phi_v)$.
  \textit{Source: [FYZ], \S2.2.}
  Let \(\om_F\) be the generic fiber of \(\om_X\). The Eisenstein series admits a
  Fourier expansion indexed by \(T \in \Herm_n(F, \om_F)\):
  \[
    E(g, s, \Phi) = \sum_{T \in \Herm_n(F, \om_F)} E_T(g, s, \Phi),
  \]
  where
  \[
    E_T(g, s, \Phi) = \int_{N_n(F) \backslash N_n(\BA)}
      E(n(b)\, g, s, \Phi)\, \psi_0(\langle T, b \rangle)\, dn(b),
  \]
  with \(\langle T, b \rangle = \mathrm{Res}(-\mathrm{Tr}(Tb))\) and the Haar measure
  \(dn(b)\) normalized so that \(N_n(F) \backslash N_n(\BA)\) has volume \(1\). For
  \emph{nonsingular} \(T\) (non-vanishing determinant) and factorizable
  \(\Phi = \bigotimes_v \Phi_v\), the Fourier coefficient factorizes as in
  Lemma~\ref{lem:fourier-coeff-factorization}.
\end{definition}

\begin{definition}[Local Whittaker function]
  \label{def:local-whittaker}
  \lean{HSW.LocalWhittakerFunction}
  \uses{def:siegel-parabolic}
  % SOURCE: [FYZ], §2.2 Fourier expansion (read from references/MR4689373-siegel-weil-unitary.tex)
  % SOURCE QUOTE: the \emph{local (generalized) Whittaker function} is defined by $W_{T,v}(g_v, s, \Phi_v)=\int_{N_n(F_{v})}\Phi_v(w_n^{-1}n(b)g_v,s) \psi_{0}(\j{T,b}_{v}) \, \rd_{v} n(b),\quad w_n= \begin{pmatrix} 0  & 1_n\\   -1_n & 0\\ \end{pmatrix}$ and has analytic continuation to $s\in \mathbb{C}$. Here the local Haar measure $\rd_{v} n(b)$ is the one such that the volume of $N_{n}(\cO_{v})$ is $1$.
  \textit{Source: [FYZ], \S2.2.}
  The \emph{local Whittaker function} is
  \[
    W_{T,v}(g_v, s, \Phi_v) = \int_{N_n(F_v)}
      \Phi_v\!\bigl(w_n^{-1} n(b)\, g_v,\, s\bigr)\,
      \psi_0(\langle T, b \rangle_v)\, d_v n(b),
    \quad w_n = \begin{pmatrix} 0 & 1_n \\ -1_n & 0 \end{pmatrix},
  \]
  where \(d_v n(b)\) is normalized so that \(N_n(\cO_v)\) has volume \(1\). It
  admits analytic continuation to all \(s \in \mathbf{C}\).
\end{definition}

\begin{lemma}[Fourier coefficient factorization]
  \label{lem:fourier-coeff-factorization}
  \lean{HSW.fourierCoeffFactorization}
  \uses{def:fourier-coefficient, def:local-whittaker}
  % SOURCE: [FYZ], §2.2 Fourier expansion (read from references/MR4689373-siegel-weil-unitary.tex)
  % SOURCE QUOTE: Suppose $T$ is \emph{nonsingular}, meaning that for one (equivalently, any) choice of trivialization of $\omega_F$ it has non-vanishing determinant, for a factorizable $\Phi=\bigotimes_{v\in|X|}\Phi_v$ we have a factorization of the Fourier coefficient into a product (cf. \cite[\S 4]{Kudla1997}) $E_T(g,s,\Phi)=|\om_{X}|_{F}^{-n^{2}/2}\prod_v W_{T,v}(g_v, s, \Phi_v)$.
  \textit{Source: [FYZ], \S2.2 (cf.\ Kudla 1997, \S4).}
  For nonsingular \(T \in \Herm_n(F, \om_F)\) and factorizable
  \(\Phi = \bigotimes_v \Phi_v\),
  \[
    E_T(g, s, \Phi) = |\om_X|_F^{-n^2/2} \prod_v W_{T,v}(g_v, s, \Phi_v).
  \]
\end{lemma}

\begin{proof}
  \uses{def:fourier-coefficient, def:local-whittaker}
  Standard: follows from the Iwasawa decomposition and local-global compatibility of
  the Weil representation. The factor \(|\om_X|_F^{-n^2/2}\) is the ratio between the
  global Haar measure \(dn(b)\) and the product of the local measures
  \(\prod_v d_v n(b)\). See Kudla (1997), \S4.
\end{proof}

\section{Local densities for Hermitian lattices}

\begin{definition}[Local density]
  \label{def:local-density}
  \lean{HSW.LocalDensity}
  \uses{def:base-curve}
  % SOURCE: [FYZ], §2.3 Local densities for Hermitian lattices (read from references/MR4689373-siegel-weil-unitary.tex)
  % SOURCE QUOTE: The \emph{local density} of integral representations of $M$ by $L$ is defined to be $$\Den(M,L)\colon= \lim_{N\rightarrow +\infty}\frac{\#\Rep_{M,L}(\cO_F/\varpi^N)}{q^{N\cdot\dim (\Rep_{M,L})_{F}}}.$$ Note that if $L, M$ have $\cO_{F'}$-rank $n, m$ respectively and the generic fiber $(\Rep_{M,L})_{F}\ne\varnothing$, then $n\le m$ and $\dim (\Rep_{M,L})_{F}=\dim \U_m-\dim \U_{m-n}= n\cdot (2m-n)$.
  \textit{Source: [FYZ], \S2.3.}
  Let \(F\) be a non-archimedean local field with \(\mathrm{char}(F) \neq 2\),
  \(F'/F\) either an unramified quadratic extension or \(F \times F\), and let
  \(L, M\) be Hermitian \(\cO_{F'}\)-lattices with \(\cO_{F'}\)-ranks \(n\) and \(m\)
  respectively. The \emph{local density} of integral representations of \(M\) by
  \(L\) is
  \[
    \Den(M, L) := \lim_{N \to +\infty}
      \frac{\# \Rep_{M,L}(\cO_F / \varpi^N)}{q^{N \cdot \dim(\Rep_{M,L})_F}},
  \]
  where \(\Rep_{M,L}\) is the scheme of Hermitian \(\cO_F\)-algebra homomorphisms from
  \(L\) to \(M\). When the generic fiber \((\Rep_{M,L})_F \neq \varnothing\), one has
  \(n \leq m\) and \(\dim(\Rep_{M,L})_F = n(2m - n)\).
\end{definition}

\section{Cho--Yamauchi formula for local density}

\begin{definition}[Local Siegel series]
  \label{def:local-siegel-series}
  \lean{HSW.LocalSiegelSeries}
  \uses{def:local-density}
  % SOURCE: [FYZ], Theorem 2.3(2) (read from references/MR4689373-siegel-weil-unitary.tex)
  % SOURCE QUOTE: There is  a (unique) polynomial $\Den(T,L)\in \mathbb{Z}[T]$, called  (normalized) \emph{local Siegel series} of $L$,  such that for all $j\geq 0$, $$\Den((\eta(\varpi) q)^{-j},L)=\frac{\Den(\iden^{n+j}, L)}{\Den(\iden^{n+j}, \iden^n)}.$$
  \textit{Source: [FYZ], Theorem~2.3(2).}
  There is a unique polynomial \(\Den(T, L) \in \mathbf{Z}[T]\), called the
  \emph{(normalized) local Siegel series} of \(L\), characterized by
  \[
    \Den\bigl((\eta(\varpi) q)^{-j},\, L\bigr) =
      \frac{\Den(\mathbf{1}^{n+j},\, L)}{\Den(\mathbf{1}^{n+j},\, \mathbf{1}^n)}
    \quad \text{for all } j \geq 0,
  \]
  where \(\mathbf{1}^m\) denotes the self-dual Hermitian \(\cO_{F'}\)-lattice of
  rank \(m\) with Hermitian form given by the identity matrix.
\end{definition}

\begin{theorem}[Cho--Yamauchi formula]
  \label{thm:cho-yamauchi}
  \lean{HSW.choYamauchi}
  \uses{def:local-siegel-series, def:local-density}
  % SOURCE: [FYZ], Theorem 2.3 (read from references/MR4689373-siegel-weil-unitary.tex)
  % SOURCE QUOTE: \begin{thm}\label{th:CY} Let $j\ge0$ be an integer. Let $\iden^j$ be the self-dual Hermitian $\cO_{F'}$-lattice of rank $j$ with Hermitian form given the identity matrix $\mathbf{1}_j$. Let $L$ be a Hermitian $\cO_{F'}$-lattice of rank $n$. ... There is  a (unique) polynomial $\Den(T,L)\in \mathbb{Z}[T]$, called  (normalized) \emph{local Siegel series} of $L$,  such that for all $j\geq 0$, $\Den((\eta(\varpi) q)^{-j},L)=\frac{\Den(\iden^{n+j}, L)}{\Den(\iden^{n+j}, \iden^n)}.$ ... We have $\Den(T,L) = \sum_{L \subset L '\subset L'^{\vee} \subset L^{\vee}} T^{2\ell'(L'/L)}\fm(  t'(L');T).$ Here the sum is over $\cO_{F'}$-lattices $L'$ (in the $F'$-Hermitian space spanned by $L$) containing $L$ on which the Hermitian form is integral.
  \textit{Source: [FYZ], Theorem~2.3.}
  For a Hermitian \(\cO_{F'}\)-lattice \(L\) of rank \(n\), the normalized local
  Siegel series is
  \[
    \Den(T, L) = \sum_{L \subset L' \subset L'^\vee \subset L^\vee}
      T^{2\ell'(L'/L)}\, \mathfrak{m}(t'(L');\, T),
  \]
  where the sum is over \(\cO_{F'}\)-lattices \(L'\) containing \(L\) in the
  \(F'\)-Hermitian space spanned by \(L\) on which the Hermitian form is integral, and
  \[
    \mathfrak{m}(a;\, T) := \prod_{i=0}^{a-1}\bigl(1 - (\eta(\varpi) q)^i T\bigr)
      \in \mathbf{Z}[T].
  \]
  Here \(\ell'(\cdot)\) denotes length as an \(\cO_{F'}\)-module and \(t'(L')\) is the
  \(k'\)-rank of the radical of \(L' \otimes_{\cO_F} k\).
\end{theorem}

% SOURCE QUOTE PROOF: The non-split case is proved in \cite[Thm.~3.5.1]{LZ1} and here we indicate the necessary change in the split case.  Now suppose $F'=F\times F$ and hence $k'=k\times k$. Let $L_k=L\otimes_{\cO_F} k$ and $\iden^m_{k}=\iden^m\otimes_{\cO_F} k$, which are free $k'$-modules with the induced $k'/k$-Hermitian forms. In particular, $\iden^m_{k}$ is non-degenerate and the radical of $L_k=L\otimes_{\cO_F} k$  has $k'$-rank equal to $t'(L)=t(L_1^\vee/L_1)=t(L_2^\vee/L_2)$. Let $\Isom_{\iden^m_{k}, L_k}$ be the $k$-scheme of ``isometric embeddings'' from $L_k$ to  $\iden^m_{k}$, i.e., {\em injective} $k'$-linear maps from $L_k$ to  $\iden^m_{k}$ preserving the Hermitian forms. ... It remains to show that $\#\Isom_{\iden^m_{k}, L_k}(k)= q^{m^2-(m-n)^2}\cdot \prod_{i=0}^{n+a-1}(1-q^{i-m})$ where $a=t'(L)$ ... By \eqref{eq:k pts1} ... it suffices to show \eqref{eq:k pts} in the two extreme cases: $a=0$ and $a=n$.
\begin{proof}
  \uses{def:local-density, def:local-siegel-series}
  The non-split case is [LZ22a, Thm.~3.5.1]. For the split case \(F' = F \times F\),
  one reduces to counting isometric embeddings over the residue field. Writing
  \(L_k = L \otimes_{\cO_F} k\), a direct computation shows
  \[
    \# \mathrm{Isom}_{\mathbf{1}^m_k, L_k}(k)
      = q^{m^2-(m-n)^2} \prod_{i=0}^{n+a-1}(1 - q^{i-m}),
    \quad a = t'(L),
  \]
  using the splitting formula
  \(\# \mathrm{Isom}(V_m, U_{n-a,a}) = \# \mathrm{Isom}(V_m, U_{n-a,0})
    \cdot \# \mathrm{Isom}(V_{m-(n-a)}, U_{0,a})\),
  which reduces to the two extremes \(a = 0\) and \(a = n\), each verified by a
  count of injective linear maps between \(k\)-vector spaces.
\end{proof}

% archon:future-covers MR4689373HigherSiegelWeilFormulaForUnitaryGroupsTheNonSingularTerms/Geometric.lean
\label{chap:geometric-side}

This chapter formalizes Phase~P2 of the project: the geometric construction of the virtual
fundamental class \([\cZ_{\cE}^r(a)] \in \Ch_0(\cZ_{\cE}^r(a))_{\mathbf{Q}}\). The key
steps are: (1) define the Hermitian shtuka chain model for special cycles; (2) establish
the virtual class in the line-bundle case via intersection products; (3) introduce good framings
to reduce the general case; (4) prove independence of framing; (5) establish properness and
the well-definedness of the degree. We follow \S\S5--10 of Feng--Yun--Zhang [MR4689373].

\section{Moduli of hermitian shtukas}

\begin{definition}[Hermitian shtuka chain]
  \label{def:herm-shtuka-chain}
  \lean{HSW.HermShtukaChain}
  \uses{def:hermitian-shtukas-stack, def:etale-cover, def:serre-dual-vb, def:hermitian-map}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §5.1–5.2
  % SOURCE QUOTE: "classify chains of vector bundles with Hermitian structures
  %   \(\cF_0 \dashrightarrow \cF_1 \dashrightarrow \cdots \dashrightarrow \cF_r \cong {}^\tau\cF_0\)
  %   related by elementary modifications"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S5.1--5.2.}
  A \emph{rank-\(n\) Hermitian shtuka chain of level \(r\)} over a test scheme \(S\) is
  a diagram of rank-\(n\) vector bundles
  \[
    \cE_0 \xleftarrow{\;f_1\;} \cE_1 \xleftarrow{\;f_2\;} \cdots \xleftarrow{\;f_r\;}
    \cE_r
  \]
  on \(X' \times S\), together with Hermitian structures
  \(h_i : \cE_i \xrightarrow{\sim} \sigma^*\cE_i^\vee\) and an isomorphism
  \(\varphi : \cE_r \xrightarrow{\sim} \sigma^*\cE_0^\vee\) compatible with all \(h_i\),
  such that:
  \begin{enumerate}
    \item Each \(f_i : \cE_i \to \cE_{i-1}\) is an \emph{elementary modification}: an
      injective bundle map whose cokernel is a skyscraper sheaf at a single closed point
      \(x'_i \in X'(S)\) of length \(1\).
    \item The composite
      \(\cE_0 \hookrightarrow \cdots \hookrightarrow \cE_r \xrightarrow{\varphi}
      \sigma^*\cE_0^\vee\)
      is an injective Hermitian map (Definition~\ref{def:hermitian-map}).
  \end{enumerate}
  The moduli functor of such chains represents a locally Noetherian algebraic stack, which
  is the explicit model of \(\Sht_{\U(n)}^r\) (Definition~\ref{def:hermitian-shtukas-stack}).
\end{definition}

\section{Special cycles: basic properties}

\begin{lemma}[Virtual dimension in the line-bundle case]
  \label{lem:line-bundle-dim}
  \lean{HSW.lineBundleVirtualDim}
  \uses{def:herm-shtuka-chain, def:special-cycle, def:base-curve}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §6.1–6.3
  % SOURCE QUOTE: "when \(\cL\) is a line bundle and \(a:\cL\to\sigma^*\cL^\vee\) is an
  %   injective Hermitian map, \(\cZ_\cL^r(a)\) has the expected dimension"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S6.1--6.3.}
  When \(n = 1\) (i.e., \(\cE = \cL\) is a line bundle) and
  \(a : \cL \to \sigma^*\cL^\vee\) is an injective Hermitian map, the special cycle
  \(\cZ_{\cL}^r(a)\) has virtual dimension \(0\): the expected codimension \(r\) cut
  in \(\Sht_{\U(1)}^r\) (which has virtual dimension \(r\)) is achieved exactly.
\end{lemma}

\begin{proof}
  \uses{def:herm-shtuka-chain, def:special-cycle}
  The moduli stack \(\Sht_{\U(1)}^r\) has virtual dimension \(r\): each elementary
  modification in the shtuka chain contributes \(1\) to the dimension count
  (a point of \(X'\)), giving \(r\) parameters. The Hermitian condition imposed by
  \(a\) is a degree-\(r\) closed condition that cuts out a zero-dimensional substack.
  Formally, the \(r\) elementary modifications at legs \(x'_1, \ldots, x'_r \in X'(S)\)
  together with the constraint that the composite map equals \(a\) impose \(r\) scalar
  conditions (one per leg) on the \(r\)-dimensional space of legs, leaving virtual
  dimension \(0\).
\end{proof}

\begin{definition}[Virtual class in the line-bundle case]
  \label{def:virtual-class-lb}
  \lean{HSW.VirtualClassLineBdl}
  \uses{lem:line-bundle-dim, def:special-cycle, def:base-curve, def:virtual-fundamental-class}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §6.4–6.6
  % SOURCE QUOTE: "the class \([\cZ_\cE^r(a)]\in\Ch_0(\cZ_\cE^r(a))_\mathbf{Q}\) can be
  %   defined as (the restriction to \(\cZ_\cE^r(a)\) of) the intersection product of
  %   \(\cZ_{\cL_i}^r(a_{ii})\) for the diagonal entries \(a_{ii}\) of \(a\)"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S6.4--6.6.}
  For a line bundle \(\cL\) on \(X'\) and an injective Hermitian map
  \(a : \cL \to \sigma^*\cL^\vee\), the \emph{virtual fundamental class}
  \[
    [\cZ_{\cL}^r(a)] \in \Ch_0(\cZ_{\cL}^r(a))_{\mathbf{Q}}
  \]
  is defined as the intersection product of the \(r\) relative effective Cartier divisors
  \(D_1, \ldots, D_r\) on \(\Sht_{\U(1)}^r\), where \(D_i\) is the divisor defined by the
  \(i\)-th elementary modification \(\cE_{i-1} \leftarrow \cE_i\) (i.e., the zero locus
  of the modification map viewed as a section of a line bundle). The intersection
  \(D_1 \cdot D_2 \cdots D_r\) lies in \(\Ch_0\) by Lemma~\ref{lem:line-bundle-dim}.
\end{definition}

\begin{theorem}[Properness of the special cycle]
  \label{thm:properness-shtuka-full}
  \lean{HSW.properSpecialCycleFull}
  \uses{def:herm-shtuka-chain, lem:properness-special-cycle, def:hermitian-map}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §"Corank n special cycles", Prop. (prop: KR cycle proper)
  % SOURCE QUOTE: "Then $\cZ^{r}_{\cE}(a)$ is a proper scheme over $k$ that depends only on
  %   the torsion sheaf $\cQ=\coker(a)=\s^{*}\cE^{\vee}/\cE$ together with the Hermitian structure"
  \textit{Source: Feng--Yun--Zhang [MR4689373], Proposition~``KR cycle proper''.}
  Let \(a : \cE \to \sigma^*\cE^\vee\) be injective. The algebraic stack
  \(\cZ_{\cE}^r(a)\) is proper over \(\mathrm{Spec}(\mathbf{F}_q)\).
\end{theorem}

\begin{proof}
  \uses{def:herm-shtuka-chain, lem:properness-special-cycle}
  The Hermitian shtuka chain \((\cE_0, \ldots, \cE_r)\) in \(\cZ_{\cE}^r(a)\) is
  bounded: the modification loci \(x'_1, \ldots, x'_r \in X'\) are constrained by
  the composite map equaling the fixed injective \(a\), so the legs are confined to
  a proper closed subscheme of \((X')^r\). Specifically, the cokernel of the composite
  \(\cE_r \hookrightarrow \cE_0 \xrightarrow{a} \sigma^*\cE_0^\vee\) must be
  zero (by injectivity of \(a\)), which forces the shtuka chain to be globally bounded.
  Properness then follows from the paper's Proposition ``KR cycle proper'' (quoted in
  Lemma~\ref{lem:properness-special-cycle}): \(\cZ_\cE^r(a) \subset \Sht_{\U(n)}^r\)
  is a closed substack of a proper stack.
\end{proof}

\section{Hitchin-type moduli spaces}

\begin{definition}[Good framing]
  \label{def:good-framing}
  \lean{HSW.GoodFraming}
  \uses{def:herm-shtuka-chain, def:special-cycle, def:etale-cover}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §8.1–8.3
  % SOURCE QUOTE: "introducing the notion of a \emph{good framing} for \(\cE\) to reduce
  %   to the case of a sum of line bundles"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S8.1--8.3.}
  Let \(\cE\) be a rank-\(n\) vector bundle on \(X'\) with an injective Hermitian map
  \(a : \cE \to \sigma^*\cE^\vee\). A \emph{good framing} for \((\cE, a)\) is a
  datum \((\cL_1, \ldots, \cL_n, \phi)\) consisting of line bundles \(\cL_i\) on
  \(X'\) and an isomorphism
  \[
    \phi : \cL_1 \oplus \cdots \oplus \cL_n \xrightarrow{\;\sim\;} \cE
  \]
  such that the induced Hermitian map
  \(a_\phi := \phi^{-1} \circ a \circ \phi : \bigoplus \cL_i \to
  \sigma^*\bigoplus \cL_i^\vee\)
  is diagonal (i.e., \(a_\phi = \mathrm{diag}(a_{11}, \ldots, a_{nn})\) with each
  \(a_{ii} : \cL_i \to \sigma^*\cL_i^\vee\) injective Hermitian).
  Good framings exist after passing to an étale cover of the base \(S\).
\end{definition}

\begin{lemma}[Independence of framing]
  \label{lem:framing-independence}
  \lean{HSW.framingIndependence}
  \uses{def:good-framing, def:virtual-class-lb, def:special-cycle}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §§9–10
  % SOURCE QUOTE: "we ... verif[y] independence of the choice [of framing]"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S\S9--10.}
  For any two good framings \(\phi_1, \phi_2\) of \((\cE, a)\), the virtual fundamental
  classes they define in \(\Ch_0(\cZ_{\cE}^r(a))_{\mathbf{Q}}\) are equal.
\end{lemma}

\begin{proof}
  \uses{def:good-framing, def:virtual-class-lb}
  Any two good framings differ by an element \(g \in \GL_n\) (acting on
  \(\bigoplus \cL_i\)), and the diagonal Hermitian maps transform by
  \(a \mapsto g \cdot a \cdot {}^t\bar{g}\). The intersection class
  \([\cZ_{\cE}^r(a_\phi)] = \prod_i [\cZ_{\cL_i}^r(a_{ii})]\) depends only on the
  diagonal entries \(a_{ii}\), which transform by the \(\GL_n\)-action.  A direct
  computation on intersection products shows the class is invariant under this
  action: the permutation matrix \(S_n\)-action on the \(\cL_i\) permutes the
  factors of the product, and the \((\mathbf{Z}/2\mathbf{Z})^n\)-action (changing
  sign of some \(a_{ii}\)) preserves injectivity and the class. Independence then
  follows by descent, since good framings form an étale torsor.
\end{proof}

\section{Comparison of two cycle classes}

\begin{definition}[Virtual fundamental class: construction]
  \label{def:virtual-class-full}
  \lean{HSW.VirtualClassFull}
  \uses{def:good-framing, lem:framing-independence, thm:properness-shtuka-full,
        def:virtual-class-lb, def:virtual-fundamental-class, def:degree-special-cycle}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §10.4
  % SOURCE QUOTE: "we are able to construct an appropriate ``virtual fundamental cycle''
  %   \([\cZ_\cE^r(a)] \in \Ch_0(\cZ_\cE^r(a))_\mathbf{Q}\)"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S10.4.}
  For a rank-\(n\) vector bundle \(\cE\) on \(X'\) and injective Hermitian \(a\),
  the virtual fundamental class
  \[
    [\cZ_{\cE}^r(a)] \in \Ch_0(\cZ_{\cE}^r(a))_{\mathbf{Q}}
  \]
  is constructed by choosing any good framing \(\phi\) (Definition~\ref{def:good-framing}),
  applying Definition~\ref{def:virtual-class-lb} to the line-bundle case to obtain a class
  \([\cZ_{\bigoplus \cL_i}^r(a_\phi)]\), and transporting via \(\phi^{-1}\). By
  Lemma~\ref{lem:framing-independence} this is independent of \(\phi\). By
  Theorem~\ref{thm:properness-shtuka-full}, \(\cZ_{\cE}^r(a)\) is proper over
  \(\mathbf{F}_q\), so the degree map
  \[
    \deg : \Ch_0(\cZ_{\cE}^r(a))_{\mathbf{Q}} \to \mathbf{Q}
  \]
  is well-defined (counting \(\mathbf{F}_q\)-points with automorphism-group weights).
  This construction fulfills the P0 axiom of Definition~\ref{def:virtual-fundamental-class}
  and makes \(\deg[\cZ_{\cE}^r(a)] \in \mathbf{Q}\) the right-hand side of
  Theorem~\ref{thm:higher-siegel-weil}.
\end{definition}

% archon:future-covers MR4689373HigherSiegelWeilFormulaForUnitaryGroupsTheNonSingularTerms/HermitianSpringer.lean
\label{chap:hermitian-springer}

This chapter formalizes Phase~P3a of the project: the Hermitian analogue of Laumon's
Springer sheaf on \(\mathrm{Coh}_d(X)\). The objects here are the moduli stack
\(\Herm_{2d}(X'/X)\) of Hermitian torsion sheaves, its Grothendieck--Springer resolution
\(\widetilde{\Herm}_{2d}(X'/X)\), and the resulting Hermitian Springer sheaf
\(\mathrm{Spr}^{\mathrm{Herm}}_{2d}\) with its canonical \(W_d\)-action and
decomposition into isotypical summands. We follow \S\S3--4 of Feng--Yun--Zhang
[MR4689373].

\section{Springer theory for Hermitian torsion sheaves}

\subsection{Local geometry of $\Herm_{d}$}

\begin{definition}[Moduli stack of Hermitian torsion sheaves]
  \label{def:herm-torsion-stack}
  \lean{HSW.HermTorsionStack}
  \uses{def:etale-cover, def:serre-dual-vb, def:base-curve}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §3.1
  % SOURCE QUOTE: "\(\Herm_{2d}(X'/X)\) parameterizes pairs \((\cQ,\iota)\) where
  %   \(\cQ\) is a torsion sheaf on \(X'\) of length \(2d\) and
  %   \(\iota:\cQ\xrightarrow{\sim}\sigma^*\cQ^\vee\) is a Hermitian structure"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S3.1.}
  For \(d \geq 0\), the moduli stack \(\Herm_{2d}(X'/X)\) parameterizes pairs
  \((\cQ, \iota)\) where:
  \begin{enumerate}
    \item \(\cQ\) is a coherent torsion sheaf on \(X'\) of \(\mathcal{O}_{X'}\)-length
      \(2d\) (i.e., a rank-0 coherent sheaf supported at finitely many closed points,
      with total length \(2d\));
    \item \(\iota : \cQ \xrightarrow{\;\sim\;} \sigma^*\cQ^\vee\) is a
      \emph{Hermitian structure}, where \(\cQ^\vee = \underline{\mathrm{Ext}}^1(\cQ,
      \om_{X'})\) is the Serre dual of \(\cQ\) (Definition~\ref{def:serre-dual-vb})
      and \(\sigma\) is the involution of \(X'/X\) (Definition~\ref{def:etale-cover}).
  \end{enumerate}
  The stack \(\Herm_{2d}(X'/X)\) is an algebraic stack locally of finite type over
  \(\mathbf{F}_q\), stratified by the isomorphism type of \(\cQ\) as a
  \(\sigma\)-equivariant torsion sheaf.
\end{definition}

\subsection{The Hermitian Springer sheaf}

\begin{definition}[Hermitian Springer resolution]
  \label{def:herm-springer-resolution}
  \lean{HSW.HermSpringerResolution}
  \uses{def:herm-torsion-stack, def:etale-cover}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §ss:Herm Spr (The Hermitian Springer sheaf)
  % SOURCE QUOTE: "$\wt\Herm_{d}(X'/X)$ ... classifying $(\cQ,h)\in \Herm_{d}(X'/X)$ together with a full flag
  %   $0\subset \cQ_{1}\subset \cdots \subset \cQ_{i}\subset \cdots \subset \cQ_{d-1}=\cQ_{1}^{\bot}\subset \cQ_{d}=\cQ$,
  %   where $\cQ_{i}$ has length $i$ and $\cQ_{d-i}=\cQ_{i}^{\bot}$"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S``The Hermitian Springer sheaf''.}
  The \emph{Hermitian Springer resolution} is the algebraic stack
  \(\widetilde{\Herm}_{2d}(X'/X)\) parameterizing \emph{full} flags of sub-sheaves
  \[
    0 = \cQ_0 \subset \cQ_1 \subset \cdots \subset \cQ_i \subset \cdots
      \subset \cQ_{2d} = \cQ
  \]
  in which each step has length \(1\), i.e.\ \(\cQ_i\) has length \(i\) for
  \(i = 0, 1, \ldots, 2d\), together with the Hermitian structure \(\iota\) on
  \(\cQ = \cQ_{2d}\), subject to the isotropy constraint
  \(\cQ_{2d-i} = \cQ_i^{\bot}\) for all \(i\) (orthogonal complement under the
  Hermitian pairing). The forgetful map
  \[
    \tilde\pi : \widetilde{\Herm}_{2d}(X'/X) \to \Herm_{2d}(X'/X),
    \quad (\cQ_\bullet) \mapsto \cQ_{2d},
  \]
  is a proper representable morphism of algebraic stacks.
\end{definition}

\begin{definition}[Hermitian Springer sheaf]
  \label{def:springer-sheaf-herm}
  \lean{HSW.HermSpringerSheaf}
  \uses{def:herm-springer-resolution, def:herm-torsion-stack}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §3.4–4.1
  % SOURCE QUOTE: "the perverse sheaf \(\mathrm{Spr}^\Herm_{2d}:=\tilde\pi_*\Ql\)
  %   ... carries a canonical action of the group
  %   \(W_d=(\BZ/2\BZ)^d\rtimes S_d\)"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S3.4--4.1.}
  The \emph{Hermitian Springer sheaf} is the direct image perverse sheaf
  \[
    \mathrm{Spr}^{\mathrm{Herm}}_{2d} := \tilde\pi_*\, \Ql
    \;\in\; \mathrm{Perv}(\Herm_{2d}(X'/X),\, \Ql),
  \]
  where \(\Ql = \overline{\mathbf{Q}}_\ell\) is the \(\ell\)-adic coefficient field.
  By the Decomposition Theorem (Beilinson--Bernstein--Deligne--Gabber), since
  \(\tilde\pi\) is proper, \(\tilde\pi_*\Ql\) is semisimple.
  The Weyl group \(W_d = (\mathbf{Z}/2\mathbf{Z})^d \rtimes S_d\) acts on
  \(\mathrm{Spr}^{\mathrm{Herm}}_{2d}\) by Hecke correspondences:
  \begin{itemize}
    \item the \(S_d\)-action permutes the steps of the flag \((\cQ_\bullet)\);
    \item the \((\mathbf{Z}/2\mathbf{Z})^d\)-action applies the Hermitian involution
      \(\iota\) on individual graded pieces \(\cQ_i/\cQ_{i-1}\).
  \end{itemize}
  This is the Hermitian analogue of Laumon's Springer sheaf on \(\mathrm{Coh}_d(X)\).
\end{definition}

\subsection{The action of $W_{d}$}

\begin{theorem}[Decomposition of the Hermitian Springer sheaf]
  \label{thm:springer-decomp}
  \lean{HSW.springerDecomp}
  \uses{def:springer-sheaf-herm, def:herm-torsion-stack}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §4.2–4.3
  % SOURCE QUOTE: "we ... decompose \(\mathrm{Spr}^\Herm_{2d}\) into isotypical
  %   summands \(\bigoplus_\chi V_\chi\otimes\mathrm{IC}_\chi\)"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S4.2--4.3.}
  There is a canonical \(W_d\)-equivariant decomposition
  \[
    \mathrm{Spr}^{\mathrm{Herm}}_{2d}
    \;\cong\;
    \bigoplus_{\chi \in \mathrm{Irr}(W_d)}
    V_\chi \otimes_{\Ql} \mathrm{IC}_\chi
  \]
  in \(\mathrm{Perv}(\Herm_{2d}(X'/X), \Ql)\), where:
  \begin{itemize}
    \item \(\mathrm{Irr}(W_d)\) is the set of irreducible \(\Ql\)-representations of
      \(W_d\), parameterized by bipartitions \((\lambda, \mu)\) with
      \(|\lambda| + |\mu| = d\);
    \item \(V_\chi\) is the underlying \(\Ql\)-vector space of the irreducible
      representation \(\chi\) of \(W_d\);
    \item \(\mathrm{IC}_\chi\) is the intersection cohomology complex on
      \(\Herm_{2d}(X'/X)\) associated to the \(\chi\)-isotypical local system on
      the open stratum.
  \end{itemize}
  The multiplicity of \(\mathrm{IC}_\chi\) in \(\mathrm{Spr}^{\mathrm{Herm}}_{2d}\)
  is \(\dim_{\Ql} V_\chi\).
\end{theorem}

\begin{proof}
  \uses{def:springer-sheaf-herm, def:herm-torsion-stack}
  By the Decomposition Theorem (BBD), since
  \(\tilde\pi : \widetilde{\Herm}_{2d} \to \Herm_{2d}\) is proper,
  \(\tilde\pi_*\Ql\) is a semisimple object in the derived category. Its
  perverse cohomology sheaves are semisimple perverse sheaves; since \(\tilde\pi\)
  is of relative dimension \(0\) generically, the main constituent is
  \(\mathrm{Spr}^{\mathrm{Herm}}_{2d} = \tilde\pi_*\Ql\) itself.
  The \(W_d\)-equivariance of \(\mathrm{Spr}^{\mathrm{Herm}}_{2d}\) (from
  Definition~\ref{def:springer-sheaf-herm}) determines the decomposition into
  isotypical summands: each summand \(\mathrm{IC}_\chi\) is the IC sheaf of the
  \(\chi\)-isotypical local system on the open stratum of \(\Herm_{2d}\) (the stratum
  of maximally split Hermitian torsion sheaves), identified using the combinatorial
  structure of the \(W_d\)-action.
\end{proof}

% archon:future-covers MR4689373HigherSiegelWeilFormulaForUnitaryGroupsTheNonSingularTerms/Assembly.lean
\label{chap:assembly}

This chapter formalizes Phase~P3d of the project: combining the results of Chapters
\ref{chap:perverse-sheaves-K} and~\ref{chap:wd-representations} to prove Theorem~1.1
(Theorem~\ref{thm:higher-siegel-weil} of Chapter~\ref{chap:overview}). The proof is a
chain of equalities — differentiation lemma, perverse sheaf isomorphism, and Frobenius
trace on the intersection side — each previously established. We follow \S\S15--16 of
Feng--Yun--Zhang [MR4689373].

\section{Matching of sheaves}

\subsection{Proof of the main theorem}

\begin{lemma}[Differentiation lemma]
  \label{lem:differentiate-q}
  \lean{HSW.differentiateQ}
  \uses{thm:trace-Eis, def:normalized-fourier-coeff, def:central-value-d, def:K-Eis}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §16.1–16.2
  % SOURCE QUOTE: "\(\frac{1}{(\log q)^r}(\dds)^r|_{s=0}(q^{ds}\wt E_a(m(\cE),s,\Phi))
  %   =\Tr(\Frob_q^{(r)},(\cK_d^\Eis)_{\bar\cQ})\)"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S16.1--16.2.}
  Let \(d \geq 0\) and \(\cQ \in \Herm_{2d}(\mathbf{F}_q)\). Using the graded
  Frobenius trace formula~\ref{thm:trace-Eis}, the \(r\)-th normalized logarithmic
  \(s\)-derivative at \(s = 0\) satisfies:
  \begin{align*}
    &\frac{1}{(\log q)^r}
    \Bigl(\frac{d}{ds}\Bigr)^r\!\Bigg|_{s=0}
    \!\bigl(q^{ds}\,\widetilde{E}_a(m(\cE), s, \Phi)\bigr)
    \\
    &\quad=
    \frac{1}{(\log q)^r}
    \Bigl(\frac{d}{ds}\Bigr)^r\!\Bigg|_{s=0}
    \Biggl(
      q^{ds} \sum_{i=0}^d
      \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Eis}}_{d,i})_{\overline{\cQ}}\bigr)\,
      q^{-2is}
    \Biggr)
    \\
    &\quad=
    \sum_{i=0}^d
    \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Eis}}_{d,i})_{\overline{\cQ}}\bigr)\cdot
    (d - 2i)^r.
  \end{align*}
  The last step uses the identity
  \(\frac{1}{(\log q)^r}(\frac{d}{ds})^r|_{s=0}(q^{(d-2i)s}) = (d-2i)^r\).
\end{lemma}

\begin{proof}
  \uses{thm:trace-Eis, def:normalized-fourier-coeff}
  Substitute the graded trace formula (Theorem~\ref{thm:trace-Eis}) into
  \(q^{ds}\widetilde{E}_a(m(\cE),s,\Phi)\):
  \[
    q^{ds}\widetilde{E}_a(m(\cE),s,\Phi)
    = \sum_{i=0}^d
    \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Eis}}_{d,i})_{\overline{\cQ}}\bigr)\,
    q^{(d-2i)s}.
  \]
  Now differentiate term by term: \((\frac{d}{ds})^r q^{(d-2i)s} =
  ((d-2i)\log q)^r\, q^{(d-2i)s}\), evaluated at \(s=0\) gives
  \(((d-2i)\log q)^r\). Dividing by \((\log q)^r\) yields \((d-2i)^r\) per term,
  completing the computation.
\end{proof}

\begin{theorem}[Main assembly]
  \label{thm:main-assembly}
  \lean{HSW.mainAssembly}
  \uses{lem:differentiate-q, thm:trace-Int, cor:K-Eis-iso-K-Int,
        thm:higher-siegel-weil, def:degree-special-cycle, def:virtual-class-full}
  % SOURCE: FYZ-HigherSiegelWeil.tex, §16.3
  % SOURCE QUOTE: "Combining steps (1)--(3), Theorem~\ref{th:intro} follows"
  \textit{Source: Feng--Yun--Zhang [MR4689373], \S16.3.}
  The higher Siegel--Weil formula (Theorem~\ref{thm:higher-siegel-weil}) holds:
  \[
    \frac{1}{(\log q)^r}
    \left(\frac{d}{ds}\right)^r\!\Bigg|_{s=0}
    \!\bigl(q^{d s}\,\widetilde{E}_a(m(\cE), s, \Phi)\bigr)
    \;=\; \deg[\cZ_{\cE}^r(a)].
  \]
\end{theorem}

\begin{proof}
  \uses{lem:differentiate-q, thm:trace-Int, cor:K-Eis-iso-K-Int}
  We chain three equalities:
  \begin{align*}
    &\frac{1}{(\log q)^r}
    \Bigl(\frac{d}{ds}\Bigr)^r\!\Big|_{s=0}
    \bigl(q^{ds}\widetilde{E}_a(m(\cE),s,\Phi)\bigr) \\
    &\overset{\text{Lem.~\ref{lem:differentiate-q}}}{=\!=\!=}
    \sum_{i=0}^d
    \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Eis}}_{d,i})_{\overline{\cQ}}\bigr)\cdot
    (d-2i)^r \\
    &\overset{\text{Cor.~\ref{cor:K-Eis-iso-K-Int}}}{=\!=\!=}
    \sum_{i=0}^d
    \Tr\!\bigl(\Frob_q,\; (\cK^{\mathrm{Int}}_{d,i})_{\overline{\cQ}}\bigr)\cdot
    (d-2i)^r \\
    &\overset{\text{Thm.~\ref{thm:trace-Int}}}{=\!=\!=}
    \deg[\cZ_{\cE}^r(a)].
  \end{align*}
  \textbf{Step~1} is Lemma~\ref{lem:differentiate-q}: differentiation converts the
  graded trace of \(\cK_d^{\mathrm{Eis}}\) at \(s = 0\) into the sum
  \(\sum_i \Tr(\cK^{\mathrm{Eis}}_{d,i}) \cdot (d-2i)^r\).

  \textbf{Step~2} uses the isomorphism \(\cK_d^{\mathrm{Eis}} \cong \cK_d^{\mathrm{Int}}\)
  (Corollary~\ref{cor:K-Eis-iso-K-Int}, Chapter~\ref{chap:wd-representations}), which
  replaces each graded stalk trace of \(\cK^{\mathrm{Eis}}_{d,i}\) with the corresponding
  trace of \(\cK^{\mathrm{Int}}_{d,i}\).

  \textbf{Step~3} applies the Frobenius trace formula for \(\cK_d^{\mathrm{Int}}\)
  (Theorem~\ref{thm:trace-Int}, Chapter~\ref{chap:perverse-sheaves-K}), which identifies
  \(\sum_i \Tr(\cK^{\mathrm{Int}}_{d,i}) \cdot (d-2i)^r\) with \(\deg[\cZ_{\cE}^r(a)]\).

  Each step is a previously proved result; the assembly is purely formal. This completes
  the proof of the main theorem.
\end{proof}
